<content>import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import React from 'react';

import { modalService } from 'Services/modalService';
import { ModalNameE } from 'Components/modal/ModalNameE';

import ErrorModal from './ErrorModal';

vi.mock('Services/modalService', () => ({
  modalService: {
    close: vi.fn(),
    isOpen: vi.fn(() => true),
    getProps: vi.fn(() => ({ message: 'Test error message' })),
  },
}));

vi.mock('Components/modal/useModalData', () => ({
  useModalData: vi.fn(() => ({
    isOpen: true,
    props: { message: 'Test error message' },
  })),
}));

describe('ErrorModal', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should render error message from modal data', () => {
    render(<ErrorModal />);

    expect(screen.getByText('Test error message')).toBeInTheDocument();
  });

  it('should have proper ARIA attributes for accessibility', () => {
    render(<ErrorModal />);

    const message = screen.getByRole('alert');

    expect(message).toHaveAttribute('aria-live', 'assertive');
    expect(message).toHaveTextContent('Test error message');
  });

  it('should render close button with proper label', () => {
    render(<ErrorModal />);

    const closeButton = screen.getByRole('button', {
      name: /close error dialog/i,
    });

    expect(closeButton).toBeInTheDocument();
    expect(closeButton).toHaveTextContent('Close');
  });

  it('should call modalService.close when close button is clicked', () => {
    render(<ErrorModal />);

    const closeButton = screen.getByRole('button', {
      name: /close error dialog/i,
    });

    fireEvent.click(closeButton);

    expect(modalService.close).toHaveBeenCalledWith(ModalNameE.ERROR);
    expect(modalService.close).toHaveBeenCalledTimes(1);
  });

  it('should render Modal with correct props', () => {
    const { container } = render(<ErrorModal />);

    expect(container.querySelector('.modal--error')).toBeInTheDocument();
  });
});
</content>
</write_file>

